int process_packet(char *buf, size_t len) {
    char local[256];
    struct header *hdr;

    // Validate minimum buffer size
    if (len < sizeof(struct header)) {
        return -1;
    }

    hdr = (struct header *)buf;

    // Validate payload_len
    if (hdr->payload_len > sizeof(local)) {
        return -1;  // Payload too large
    }

    // Validate total buffer size
    if (len < sizeof(struct header) + hdr->payload_len) {
        return -1;  // Buffer too small
    }

    // Initialize buffer
    memset(local, 0, sizeof(local));

    // Safe copy
    if (hdr->payload_len > 0) {
        memcpy(local, buf + sizeof(struct header), hdr->payload_len);
    }

